import{_ as e,o as i,c as l,ag as o}from"./chunks/framework.CAXxHpAX.js";const p=JSON.parse('{"title":"如何验证配置是否生效","description":"","frontmatter":{},"headers":[],"relativePath":"guide/verify.md","filePath":"guide/verify.md"}'),t={name:"guide/verify.md"};function r(n,a,d,u,s,h){return i(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="如何验证配置是否生效" tabindex="-1">如何验证配置是否生效 <a class="header-anchor" href="#如何验证配置是否生效" aria-label="Permalink to &quot;如何验证配置是否生效&quot;">​</a></h1><p>配置完成后,务必验证是否生效。以下是通用的验证方法。</p><h2 id="方法-1-发送测试请求" tabindex="-1">方法 1:发送测试请求 <a class="header-anchor" href="#方法-1-发送测试请求" aria-label="Permalink to &quot;方法 1:发送测试请求&quot;">​</a></h2><p>最直接的验证方式是发送一个简单请求:</p><ol><li>在工具中发起一个简单对话或代码生成请求</li><li>观察是否成功返回结果</li><li>如果成功,说明配置生效</li></ol><p><strong>注意</strong>:测试请求会消耗 API 配额,请控制测试频率。</p><h2 id="方法-2-使用工具的连接测试功能" tabindex="-1">方法 2:使用工具的连接测试功能 <a class="header-anchor" href="#方法-2-使用工具的连接测试功能" aria-label="Permalink to &quot;方法 2:使用工具的连接测试功能&quot;">​</a></h2><p>某些工具提供&quot;连接测试&quot;或&quot;验证配置&quot;功能:</p><ol><li>在设置面板中找到&quot;Test Connection&quot;或类似按钮</li><li>点击测试</li><li>观察是否显示&quot;连接成功&quot;或类似提示</li></ol><h2 id="方法-3-查看工具日志或调试信息" tabindex="-1">方法 3:查看工具日志或调试信息 <a class="header-anchor" href="#方法-3-查看工具日志或调试信息" aria-label="Permalink to &quot;方法 3:查看工具日志或调试信息&quot;">​</a></h2><p>某些工具提供日志或调试信息:</p><ol><li>打开工具的日志面板或调试模式</li><li>发起一个请求</li><li>查看日志中是否包含正确的 Base URL 和请求状态</li></ol><h2 id="方法-4-检查错误提示" tabindex="-1">方法 4:检查错误提示 <a class="header-anchor" href="#方法-4-检查错误提示" aria-label="Permalink to &quot;方法 4:检查错误提示&quot;">​</a></h2><p>如果配置有误,工具通常会返回错误提示:</p><ul><li><code>401 Unauthorized</code>:API Key 错误或无效</li><li><code>404 Not Found</code>:Base URL 错误或路径不对</li><li><code>Connection Timeout</code>:网络问题或 Base URL 不可达</li><li><code>Model Not Found</code>:模型名称错误或该模型不可用</li></ul><p>根据错误提示排查问题。</p><h2 id="验证成功的标志" tabindex="-1">验证成功的标志 <a class="header-anchor" href="#验证成功的标志" aria-label="Permalink to &quot;验证成功的标志&quot;">​</a></h2><p>配置成功的标志包括:</p><ul><li>能够正常发起请求并获得响应</li><li>工具显示&quot;连接成功&quot;或类似提示</li><li>日志中显示正确的 Base URL</li><li>没有身份验证或连接错误</li></ul><h2 id="验证失败的常见原因" tabindex="-1">验证失败的常见原因 <a class="header-anchor" href="#验证失败的常见原因" aria-label="Permalink to &quot;验证失败的常见原因&quot;">​</a></h2><p>如果验证失败,常见原因包括:</p><ul><li>API Key 填错或已失效</li><li>Base URL 填错或不可达</li><li>未保存配置或未重启工具</li><li>网络问题或服务商服务不可用</li><li>模型名称错误(如果工具要求填写模型名)</li></ul><p>根据错误提示和工具页的常见报错部分进行排查。</p>',23)])])}const q=e(t,[["render",r]]);export{p as __pageData,q as default};
